// The schedule triggers on days 28-31 to catch month-end,
// but we only want to run on the 1st of the NEXT month.
// Cron does not natively support 'last day of month', so we
// use the day-28-31 trick and guard here.
const now = new Date();
const isFirstOfMonth = now.getUTCDate() === 1;

if (!isFirstOfMonth) {
  // Not the first — do nothing, execution will show as completed with no output
  return [];
}

const year = now.getUTCFullYear();
// Month is 1-indexed for the report period (the month that just ended)
const month = now.getUTCMonth() === 0 ? 12 : now.getUTCMonth(); // January 1st reports December
const reportYear = month === 12 ? year - 1 : year;

return [{ json: { report_year: reportYear, report_month: month, run_at: now.toISOString() } }];

const lead = Array.isArray($('Fetch Lead Details').first().json)
  ? $('Fetch Lead Details').first().json[0]
  : $('Fetch Lead Details').first().json;

const sub = $('Split Per Subscription').first().json;
const reportYear = $('Is First of Month?').first().json.report_year;
const reportMonth = $('Is First of Month?').first().json.report_month;

// call count comes from content-range header (Supabase count=exact)
const callCountRaw = $('Fetch Call Count from Events').first().json;
const callCount = Array.isArray(callCountRaw) ? callCountRaw.length : 0;

const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const monthName = monthNames[reportMonth - 1];

// Upsell trigger: more than 20 calls this month → upsell opportunity
const triggerUpsell = callCount > 20;
// Plateau: 0-2 calls for this month → flag for plateau upsell
const triggerPlateau = callCount < 3;

const html = `<!DOCTYPE html>
<html>
<body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:24px;">
<h1 style="color:#1D4ED8;">${monthName} ${reportYear} — Your Monthly Report</h1>
<p>Hi,</p>
<p>Here's how your <strong>${lead.business_name}</strong> website performed in ${monthName}.</p>
<table style="width:100%;border-collapse:collapse;margin:24px 0;">
<tr style="background:#F3F4F6;">
  <td style="padding:12px;border:1px solid #E5E7EB;"><strong>Calls tracked</strong></td>
  <td style="padding:12px;border:1px solid #E5E7EB;text-align:right;"><strong>${callCount}</strong></td>
</tr>
<tr>
  <td style="padding:12px;border:1px solid #E5E7EB;">Google Search impressions</td>
  <td style="padding:12px;border:1px solid #E5E7EB;text-align:right;">— (connect GSC to enable)</td>
</tr>
</table>
${callCount === 0 ? '<p style="color:#DC2626;">No calls tracked this month. Make sure your site\'s call tracking number is the number you\'re answering. SMS us if you need to check it.</p>' : ''}
${callCount > 0 ? '<p>Good work! Every call tracked is a lead that found you through your website.</p>' : ''}
<p>To make any changes to your site, SMS us at the number you were sent in your welcome message.</p>
<p>— Preview Factory</p>
</body>
</html>`;

return [{
  json: {
    lead_id: lead.lead_id,
    business_name: lead.business_name,
    email: lead.email,
    subscription_id: sub.subscription_id,
    report_year: reportYear,
    report_month: reportMonth,
    call_count: callCount,
    report_html: html,
    trigger_upsell: triggerUpsell,
    trigger_plateau: triggerPlateau
  }
}];
